`timescale 1ns / 1ps
//////////////////////////////////////////////////////////////////////////////////

module EncryptTestBench;
    reg clk;
    reg rst;
    reg [0:127] in;
    reg [0:1919] expanded_key;
    
    wire [0:127] out;
    wire valid_data;
    wire [0:127] ff_1_2;
    wire [0:127] ff_2_3;
    wire [0:127] ff_3_4;
    wire [0:127] ff_4_5;
    wire [0:127] ff_5_6;
    wire [0:127] ff_6_7;
    wire [0:127] ff_7_8;
    wire [0:127] ff_8_9;
    wire [0:127] ff_9_10;
    wire [0:127] ff_10_11;
    wire [0:127] ff_11_12;
    wire [0:127] ff_12_13;
    wire [0:127] ff_13_14;
        
EncryptPipelined encrypt(.clk(clk),
                .rst(rst),
                .in(in),
                .expanded_key(expanded_key),
                .out(out),
                .valid_data(valid_data),
                .ff_1_2_o(ff_1_2),
                .ff_2_3_o(ff_2_3),
                .ff_3_4_o(ff_3_4),
                .ff_4_5_o(ff_4_5),
                .ff_5_6_o(ff_5_6),
                .ff_6_7_o(ff_6_7),
                .ff_7_8_o(ff_7_8),
                .ff_8_9_o(ff_8_9),
                .ff_9_10_o(ff_9_10),
                .ff_10_11_o(ff_10_11),
                .ff_11_12_o(ff_11_12),
                .ff_12_13_o(ff_12_13),
                .ff_13_14_o(ff_13_14)
                );
                
initial begin
        clk = 0;
        rst = 0;
        @(posedge clk);
        @(posedge clk);
        rst = 1;
        @(posedge clk);
        @(posedge clk);
        rst = 0;
        @(posedge clk);
        expanded_key = 1920';
        in = 128'h00000000000000000000000000000000;
        @(posedge clk);
        expanded_key = 1920';
        in = 128'h00000000000000000000000000000000;        
        @(posedge clk);
        expanded_key = 1920';
        in = 128'h00112233445566778899aabbccddeeff;  
        @(posedge clk);
        expanded_key = 1920';
        in = "Hello world!  :)";  
        @(posedge clk);
        expanded_key = 1920';
        in = 128'h00000000000000000000000000000000;
        @(posedge clk);
        expanded_key = 1920';
        in = 128'h00000000000000000000000000000000;  
        @(posedge clk);
        expanded_key = 1920';
        in = 128'h00112233445566778899aabbccddeeff; 
        @(posedge clk);
        expanded_key = 1920';
        in = "Hello world!  :)"; 
        @(posedge clk);
        expanded_key = 1920';
        in = 128'h00000000000000000000000000000000;
        @(posedge clk);
        expanded_key = 1920';
        in = 128'h00000000000000000000000000000000;        
        @(posedge clk);
        expanded_key = 1920';
        in = 128'h00112233445566778899aabbccddeeff;  
        @(posedge clk);
        expanded_key = 1920';
        in = "Hello world!  :)";
        @(posedge clk);
        expanded_key = 1920';
        in = 128'h00000000000000000000000000000000;
        @(posedge clk);
        expanded_key = 1920';
        in = 128'h00000000000000000000000000000000;   
        @(posedge clk);
        assert(valid_data == 1'b1);
        assert(out == 128'hdc95c078a2408989ad48a21492842087);               
        @(posedge clk);
        assert(valid_data == 1'b1);
        assert(out == 128'hf29000b62a499fd0a9f39a6add2e7780); 
        @(posedge clk);
        assert(valid_data == 1'b1);
        assert(out == 128'h8ea2b7ca516745bfeafc49904b496089); 
        @(posedge clk);
        assert(valid_data == 1'b1);
        assert(out == 128'h8e00ecc38998b9806a9559f59054aaa6); 
        @(posedge clk);
        assert(valid_data == 1'b1);
        assert(out == 128'hdc95c078a2408989ad48a21492842087);               
        @(posedge clk);
        assert(valid_data == 1'b1);
        assert(out == 128'hf29000b62a499fd0a9f39a6add2e7780); 
        @(posedge clk);
        assert(valid_data == 1'b1);
        assert(out == 128'h8ea2b7ca516745bfeafc49904b496089); 
        @(posedge clk);
        assert(valid_data == 1'b1);
        assert(out == 128'h8e00ecc38998b9806a9559f59054aaa6); 
        @(posedge clk);
        assert(valid_data == 1'b1);
        assert(out == 128'hdc95c078a2408989ad48a21492842087);               
        @(posedge clk);
        assert(valid_data == 1'b1);
        assert(out == 128'hf29000b62a499fd0a9f39a6add2e7780); 
        @(posedge clk);
        assert(valid_data == 1'b1);
        assert(out == 128'h8ea2b7ca516745bfeafc49904b496089); 
        @(posedge clk);
        assert(valid_data == 1'b1);
        assert(out == 128'h8e00ecc38998b9806a9559f59054aaa6);         
        @(posedge clk);
        assert(valid_data == 1'b1);
        assert(out == 128'hdc95c078a2408989ad48a21492842087);               
        @(posedge clk);
        assert(valid_data == 1'b1);
        assert(out == 128'hf29000b62a499fd0a9f39a6add2e7780);
       
end
    always #1 clk = ~clk;        
endmodule
